package temporal

import (
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
)

func TestWorkflowcheckScriptContent(t *testing.T) {
	s := GenerateWorkflowcheck()
	if !strings.HasPrefix(s, "#!/usr/bin/env bash\n") {
		t.Errorf("script must start with a bash shebang; got:\n%s", s)
	}
	for _, want := range []string{
		"Code generated by sysgo (gen/temporal). DO NOT EDIT.",
		"set -euo pipefail",
		"go install go.temporal.io/sdk/contrib/tools/workflowcheck@latest",
		"go vet \"-vettool=$bin/workflowcheck\" ./...",
		"specs/TEMPORAL.md §6",
	} {
		if !strings.Contains(s, want) {
			t.Errorf("generated script missing %q\n---\n%s", want, s)
		}
	}
}

// TestWorkflowcheckScriptIsValidBash parses the generated script with `bash -n`
// (syntax check, no execution), the shell-script analogue of the compile tests
// the Go generators run.
func TestWorkflowcheckScriptIsValidBash(t *testing.T) {
	bash, err := exec.LookPath("bash")
	if err != nil {
		t.Skip("bash not available")
	}
	dir := t.TempDir()
	path := filepath.Join(dir, "workflowcheck.sh")
	if err := os.WriteFile(path, []byte(GenerateWorkflowcheck()), 0o755); err != nil {
		t.Fatal(err)
	}
	cmd := exec.Command(bash, "-n", path)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("generated script is not valid bash: %v\n%s", err, out)
	}
}

// TestWorkflowcheckScriptDeterministic checks the generator is pure — repeated
// calls yield identical output.
func TestWorkflowcheckScriptDeterministic(t *testing.T) {
	first := GenerateWorkflowcheck()
	second := GenerateWorkflowcheck()
	if first != second {
		t.Error("GenerateWorkflowcheck is not deterministic")
	}
}
